};

Task processComplexData(int type, int value, bool flag) {
    if (type == 1) {
        if (value > 100) {
            if (flag) {
                co_await std::suspend_always{};
                if (value > 200) {
                    // more complex logic
                    co_return;
                } else {
                    co_await std::suspend_always{};
                }
            } else {
                for (int i = 0; i < value; ++i) {
                    if (i % 2 == 0) {
                        co_await std::suspend_always{};
                    }
                }
            }
        } else if (value > 50) {
            while (value > 0) {
                co_await std::suspend_always{};
                --value;
            }
        }
